compliant:
class SomeClass
{
    private void PrivateMethod() // Compliant: void method, no unused return
    {
        // Side effects only
    }

    public void PublicMethod()
    {
        PrivateMethod();
    }
}

class SomeClass
{
    private int PrivateMethod() => 42;

    public void PublicMethod()
    {
        int result = PrivateMethod(); // Compliant: return value is used
        Console.WriteLine(result);
    }
}

class DataProcessor
{
    private string ProcessData(string input)
    {
        return input.ToUpper();
    }

    public string HandleData(string data) // Compliant: return value is used
    {
        return ProcessData(data);
    }
}
